import xml.etree.ElementTree as ET
from xml.parsers.expat import ExpatError

def parse_xml_config(file_path):
    try:
        # Create parser with security restrictions
        parser = ET.XMLParser(
            encoding='utf-8',
            recover=False,
            forbid_dtd=True,
            forbid_entities=True,
            forbid_external=True
        )
        
        # Parse the XML file
        tree = ET.parse(file_path, parser)
        root = tree.getroot()
        
        # Convert to dictionary
        settings = {}
        for child in root:
            if len(child) == 0:  # Leaf node
                settings[child.tag] = child.text
            else:  # Node with children
                settings[child.tag] = {}
                for subchild in child:
                    settings[child.tag][subchild.tag] = subchild.text
        
        return settings
    
    except (ET.ParseError, ExpatError, FileNotFoundError) as e:
        raise ValueError(f"Error parsing XML file: {str(e)}")